#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct Point {
	double x, y;
};

double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

// Function to compute the polar angle of a point relative to another
double polarAngle(const Point &p, const Point &origin) {
    return atan2(p.y - origin.y, p.x - origin.x);
}

// Comparator function for sorting points by polar angle
bool comparePointsByPolarAngle(const Point& p1, const Point& p2, const Point& origin) {
    double angle1 = polarAngle(p1, origin);
    double angle2 = polarAngle(p2, origin);
    return (angle1 < angle2);
}

// Function to compute the perimeter of the convex hull
double convexHullPerimeter(std::vector<Point> const& points) {
    if (points.size() <= 3) {
        // If there are less than or equal to three points, the convex hull is trivial.
        return distance(points[0], points[(points.size()-1)%points.size()]);
    }

    // Find the point with the lowest y-coordinate and, in case of a tie, the lowest x-coordinate
    Point origin = *std::min_element(points.begin(), points.end(),
                                     [](const Point& p1, const Point& p2) {
                                         return (p1.y < p2.y || (p1.y == p2.y && p1.x < p2.x));
                                     });

    // Sort the points by polar angle with respect to the origin
    std::sort(points.begin(), points.end(),
              [origin](const Point& p1, const Point& p2) {
                  return comparePointsByPolarAngle(p1, p2, origin);
              });

    // Compute distances between consecutive points in parallel
    double totalDistance = 0.0;
    #pragma omp parallel for reduction(+ : totalDistance)
    for (size_t i = 0; i < points.size(); ++i) {
        size_t j = (i + 1) % points.size();
        totalDistance += distance(points[i], points[j]);
    }

    return totalDistance;
}
